import React from 'react';
import { useLocation, Outlet } from 'react-router-dom';
import PhotoSide from '../components/PhotoSide';
import './AuthLayout.css';

function AuthLayout() {
  const location = useLocation();
  const reverse = ['/forgot-password', '/reset-password'].includes(location.pathname);
  const isMobile = window.innerWidth < 768;
  return (
    <div className="auth-slider-container">
      <div className={`auth-slider-wrapper ${!isMobile && reverse ? 'reverse' : ''}`}>
        {/* Slide 1: Login/Register */}
        <div className="auth-slide">
          <div className="photo-side">
            <PhotoSide />
          </div>
          <div className="form-side">
            {['/login', '/register'].includes(location.pathname) && <Outlet />}
          </div>
        </div>

        {/* Slide 2: Forgot/Reset */}
        <div className="auth-slide">
          <div className="form-side">
            {['/forgot-password', '/reset-password'].includes(location.pathname) && <Outlet />}
          </div>
          <div className="photo-side">
            <PhotoSide />
          </div>
        </div>
      </div>
    </div>
  );
}

export default AuthLayout;
